part of '../app_router.dart';

bool _sessionRoleHydrated = false;
UserRole _sessionPreferredRole = UserRole.unknown;

enum _JoinEntrySource {
  manual,
  qr,
}

Future<void> _hydrateSessionRolePreference() async {
  if (_sessionRoleHydrated) {
    return;
  }
  _sessionRoleHydrated = true;
  _sessionPreferredRole = await _sessionRolePreferenceStore.loadPreferredRole();
  _sessionRoleRefreshNotifier.ping();
}

Future<void> _persistSessionRolePreference(UserRole role) async {
  _sessionPreferredRole = role;
  _sessionRoleRefreshNotifier.ping();
  await _sessionRolePreferenceStore.persistPreferredRole(role);
}

Future<void> _clearSessionRolePreference() async {
  _sessionPreferredRole = UserRole.unknown;
  _sessionRoleRefreshNotifier.ping();
  await _sessionRolePreferenceStore.clearPreferredRole();
}

Future<void> _persistCachedPassengerRoute({
  required String routeId,
  String? routeName,
}) async {
  await _cachedPassengerRouteStore.persist(
      routeId: routeId, routeName: routeName);
}

Future<void> _clearCachedPassengerRoute() async {
  await _cachedPassengerRouteStore.clear();
}

Future<_PassengerMembershipSummary?> _readCachedPassengerRoute() async {
  final cached = await _cachedPassengerRouteStore.read();
  if (cached == null) {
    return null;
  }
  return _PassengerMembershipSummary(
    routeId: cached.routeId,
    routeName: cached.routeName,
  );
}

UserRole _resolveRoutingRoleWithSessionPreference({
  required UserRole backendRole,
}) {
  if (!_sessionRoleHydrated) {
    return UserRole.unknown;
  }
  final prefersPassengerOrDriver =
      _sessionPreferredRole == UserRole.passenger ||
          _sessionPreferredRole == UserRole.driver;
  if (prefersPassengerOrDriver) {
    return _sessionPreferredRole;
  }
  if (backendRole != UserRole.unknown) {
    return backendRole;
  }
  if (_sessionPreferredRole != UserRole.unknown) {
    return _sessionPreferredRole;
  }
  return UserRole.unknown;
}

Future<void> _routeAfterAuth(
  BuildContext context, {
  required String resolvedRole,
  String? nextRole,
}) async {
  final normalizedNextRole = _resolveAuthNextRole(nextRole);
  var effectiveRole = resolvedRole;
  final switchSourceRole = _resolveRoleFromRawString(resolvedRole);

  if (normalizedNextRole == _authNextRolePassenger) {
    unawaited(_persistSessionRolePreference(UserRole.passenger));
    final user = _authCredentialGateway.currentUser;
    if (user == null || user.isAnonymous) {
      if (context.mounted) {
        context.go(_buildAuthRouteWithNextRole(_authNextRolePassenger));
      }
      return;
    }

    if (effectiveRole != _authNextRolePassenger) {
      try {
        effectiveRole = await _bootstrapCurrentProfile(
          preferredRole: _authNextRolePassenger,
        );
      } catch (_) {
        if (context.mounted) {
          _showInfo(context, CoreErrorFeedbackTokens.profilePrepareFailed);
        }
      }
    }
    if (!context.mounted) {
      return;
    }
    final destination = await _resolvePassengerHomeDestination(user);
    if (!context.mounted) {
      return;
    }
    _applyRoleSwitchNavigationPlan(
      context,
      fromRole: switchSourceRole,
      toRole: UserRole.passenger,
      targetLocation: destination,
    );
    return;
  }

  if (normalizedNextRole == _authNextRoleDriver) {
    unawaited(_persistSessionRolePreference(UserRole.driver));
    final user = _authCredentialGateway.currentUser;
    if (user == null || user.isAnonymous) {
      context.go(_buildAuthRouteWithNextRole(_authNextRoleDriver));
      return;
    }

    EnsureCurrentAuthUserDriverCorridorEntryDestinationResult?
        driverCorridorReadiness;
    if (effectiveRole != _authNextRoleDriver) {
      try {
        driverCorridorReadiness =
            await _ensureCurrentAuthUserDriverCorridorEntryDestinationUseCase
                .execute(
          EnsureCurrentAuthUserDriverCorridorEntryDestinationCommand(
            uid: user.uid,
            displayName: _resolveDisplayName(user),
          ),
        );
        effectiveRole = driverCorridorReadiness.effectiveRole.name;
      } catch (_) {
        if (!context.mounted) {
          return;
        }
        _showInfo(context, CoreErrorFeedbackTokens.profilePrepareFailed);
        context.go(AppRoutePath.roleSelect);
        return;
      }
    }

    if (!context.mounted) {
      return;
    }
    if (effectiveRole != _authNextRoleDriver) {
      _showInfo(
        context,
